package main.rice;

import main.rice.basegen.BaseSetGenerator;
import main.rice.concisegen.ConciseSetGenerator;
import main.rice.parse.ConfigFile;
import main.rice.parse.ConfigFileParser;
import main.rice.parse.InvalidConfigException;
import main.rice.test.TestCase;
import main.rice.test.TestResults;
import main.rice.test.Tester;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;
import java.util.Set;

/**
 * Entry point for generating concise test sets from a config and implementations.
 */
public class Main {

    public static Set<TestCase> generateTests(String[] args)
            throws IOException, InvalidConfigException, InterruptedException {

        if (args == null || args.length != 3) {
            throw new IllegalArgumentException("Expected args: <configPath> <solutionPath> <implDirPath>");
        }

        String configPath = args[0];
        String secondPath = args[1];
        String thirdPath = args[2];

        // Support either argument order: (config, solution, implDir) or (config, implDir, solution).
        String solutionPath;
        String implDirPath;
        if (Files.isDirectory(Path.of(secondPath)) && !Files.isDirectory(Path.of(thirdPath))) {
            implDirPath = secondPath;
            solutionPath = thirdPath;
        } else {
            solutionPath = secondPath;
            implDirPath = thirdPath;
        }

        String configContents = Files.readString(Path.of(configPath));
        ConfigFile config = new ConfigFileParser().parse(configContents);

        BaseSetGenerator baseGen = new BaseSetGenerator(config.getNodes(), config.getNumRand());
        List<TestCase> baseSet = baseGen.genBaseSet();

        Tester tester = new Tester(config.getFuncName(), solutionPath, implDirPath, baseSet);
        tester.computeExpectedResults();
        TestResults results = tester.runTests();

        return ConciseSetGenerator.setCover(results);
    }

    public static void main(String[] args)
            throws IOException, InvalidConfigException, InterruptedException {
        Set<TestCase> conciseSet = generateTests(args);
        System.out.println(conciseSet);
    }
}

package main.rice.parse;

import main.rice.node.APyNode;

import java.util.List;

/**
 * Immutable data container for parsed configuration settings.
 */
public class ConfigFile {

    private final String funcName;
    private final List<APyNode<?>> nodes;
    private final int numRand;

    public ConfigFile(String funcName, List<APyNode<?>> nodes, int numRand) {
        this.funcName = funcName;
        this.nodes = nodes;
        this.numRand = numRand;
    }

    public String getFuncName() {
        return this.funcName;
    }

    public int getNumRand() {
        return this.numRand;
    }

    public List<APyNode<?>> getNodes() {
        return this.nodes;
    }
}

package main.rice.parse;

import main.rice.node.APyNode;
import main.rice.node.PyBoolNode;
import main.rice.node.PyDictNode;
import main.rice.node.PyFloatNode;
import main.rice.node.PyIntNode;
import main.rice.node.PyListNode;
import main.rice.node.PySetNode;
import main.rice.node.PyStringNode;
import main.rice.node.PyTupleNode;

import java.util.ArrayList;
import java.util.LinkedHashSet;
import java.util.LinkedList;
import java.util.List;
import java.util.Map;

/**
 * Parses configuration JSON into a ConfigFile with fully-typed PyNode trees.
 */
public class ConfigFileParser {

    /**
     * Parse the given JSON configuration string into a ConfigFile.
     *
     * @param configContents JSON configuration contents
     * @return parsed config
     * @throws InvalidConfigException if JSON or type/domain specs are malformed
     */
    public ConfigFile parse(String configContents) throws InvalidConfigException {
        Object parsed = parseJson(configContents);
        if (!(parsed instanceof Map<?, ?> rootMapRaw)) {
            throw new InvalidConfigException("Config must be a JSON object");
        }

        @SuppressWarnings("unchecked")
        Map<String, Object> rootMap = (Map<String, Object>) rootMapRaw;

        String fname = requireString(rootMap, "fname");

        List<String> typeStrs = requireStringArray(rootMap, "types");
        List<String> exDomains = requireStringArrayEither(rootMap,
                "exhaustive domain", "exDomain");
        List<String> ranDomains = requireStringArrayEither(rootMap,
                "random domain", "ranDomain");
        int numRand = requireIntEither(rootMap, "num random", "numRand");

        if (numRand < 0) {
            throw new InvalidConfigException("num random must be non-negative");
        }

        if (typeStrs.size() != exDomains.size() || typeStrs.size() != ranDomains.size()) {
            throw new InvalidConfigException("types/domain lengths must match");
        }

        List<APyNode<?>> nodes = new ArrayList<>();
        for (int i = 0; i < typeStrs.size(); i++) {
            TypeSpec spec = parseType(typeStrs.get(i));
            APyNode<?> node = buildNode(spec);
            applyDomain(node, spec, exDomains.get(i), true);
            applyDomain(node, spec, ranDomains.get(i), false);
            nodes.add(node);
        }

        return new ConfigFile(fname, nodes, numRand);
    }

    private static String requireString(Map<String, Object> root, String key)
            throws InvalidConfigException {
        Object val = root.get(key);
        if (!(val instanceof String s)) {
            throw new InvalidConfigException("Missing or invalid field: " + key);
        }
        return s;
    }

    private static int requireIntEither(Map<String, Object> root, String keyA, String keyB)
            throws InvalidConfigException {
        Object val = root.containsKey(keyA) ? root.get(keyA) : root.get(keyB);
        if (!(val instanceof Long l)) {
            throw new InvalidConfigException("Missing or invalid integer field");
        }
        if (l > Integer.MAX_VALUE || l < Integer.MIN_VALUE) {
            throw new InvalidConfigException("Integer out of range");
        }
        return l.intValue();
    }

    private static List<String> requireStringArrayEither(Map<String, Object> root,
                                                         String keyA,
                                                         String keyB)
            throws InvalidConfigException {
        Object raw = root.containsKey(keyA) ? root.get(keyA) : root.get(keyB);
        return requireStringArrayValue(raw);
    }

    private static List<String> requireStringArray(Map<String, Object> root, String key)
            throws InvalidConfigException {
        return requireStringArrayValue(root.get(key));
    }

    private static List<String> requireStringArrayValue(Object raw)
            throws InvalidConfigException {
        if (!(raw instanceof List<?> list)) {
            throw new InvalidConfigException("Expected array of strings");
        }
        List<String> out = new ArrayList<>();
        for (Object elem : list) {
            if (!(elem instanceof String s)) {
                throw new InvalidConfigException("Expected array of strings");
            }
            out.add(s);
        }
        return out;
    }

    private static TypeSpec parseType(String typeStr) throws InvalidConfigException {
        if (typeStr == null || typeStr.isEmpty()) {
            throw new InvalidConfigException("Empty type specification");
        }
        if (containsWhitespace(typeStr)) {
            throw new InvalidConfigException("Whitespace not allowed in type specification");
        }

        TypeCursor cursor = new TypeCursor(typeStr);
        TypeSpec spec = parseTypeRec(cursor);
        if (!cursor.atEnd()) {
            throw new InvalidConfigException("Malformed type specification");
        }
        return spec;
    }

    private static TypeSpec parseTypeRec(TypeCursor cursor) throws InvalidConfigException {
        if (cursor.startsWith("bool")) {
            cursor.consume("bool");
            return TypeSpec.prim(Kind.BOOL);
        }
        if (cursor.startsWith("int")) {
            cursor.consume("int");
            return TypeSpec.prim(Kind.INT);
        }
        if (cursor.startsWith("float")) {
            cursor.consume("float");
            return TypeSpec.prim(Kind.FLOAT);
        }
        if (cursor.startsWith("str")) {
            cursor.consume("str");
            if (!cursor.consumeIf('(')) {
                throw new InvalidConfigException("str must include character domain: str(...)");
            }
            int end = cursor.indexOf(')');
            if (end < 0) {
                throw new InvalidConfigException("Malformed str type");
            }
            String chars = cursor.substring(cursor.pos(), end);
            if (chars.isEmpty() || containsWhitespace(chars)
                    || chars.contains("(") || chars.contains(")") || chars.contains(":")) {
                throw new InvalidConfigException("Malformed str character domain");
            }
            cursor.setPos(end + 1);
            return TypeSpec.str(chars);
        }
        if (cursor.startsWith("list(")) {
            cursor.consume("list(");
            TypeSpec inner = parseTypeRec(cursor);
            cursor.expect(')');
            return TypeSpec.unary(Kind.LIST, inner);
        }
        if (cursor.startsWith("tuple(")) {
            cursor.consume("tuple(");
            TypeSpec inner = parseTypeRec(cursor);
            cursor.expect(')');
            return TypeSpec.unary(Kind.TUPLE, inner);
        }
        if (cursor.startsWith("set(")) {
            cursor.consume("set(");
            TypeSpec inner = parseTypeRec(cursor);
            cursor.expect(')');
            return TypeSpec.unary(Kind.SET, inner);
        }
        if (cursor.startsWith("dict(")) {
            cursor.consume("dict(");
            TypeSpec key = parseTypeRec(cursor);
            cursor.expect(':');
            TypeSpec val = parseTypeRec(cursor);
            cursor.expect(')');
            return TypeSpec.binary(Kind.DICT, key, val);
        }

        throw new InvalidConfigException("Unknown type");
    }

    private static APyNode<?> buildNode(TypeSpec spec) {
        return switch (spec.kind) {
            case BOOL -> new PyBoolNode();
            case INT -> new PyIntNode();
            case FLOAT -> new PyFloatNode();
            case STR -> new PyStringNode(spec.charDomain);
            case LIST -> new PyListNode<>(buildNode(spec.left));
            case TUPLE -> new PyTupleNode<>(buildNode(spec.left));
            case SET -> new PySetNode<>(buildNode(spec.left));
            case DICT -> new PyDictNode<>(buildNode(spec.left), buildNode(spec.right));
        };
    }

    private static void applyDomain(APyNode<?> node,
                                    TypeSpec spec,
                                    String domainSpec,
                                    boolean exhaustive)
            throws InvalidConfigException {
        DomainCursor cursor = new DomainCursor(domainSpec);
        ParsedDomain parsed = parseDomainRec(spec, cursor);
        if (!cursor.atEnd()) {
            throw new InvalidConfigException("Malformed domain specification");
        }
        assignDomain(node, parsed, exhaustive);
    }

    private static ParsedDomain parseDomainRec(TypeSpec spec, DomainCursor cursor)
            throws InvalidConfigException {
        return switch (spec.kind) {
            case BOOL -> ParsedDomain.leaf(parseLeafValues(cursor, LeafKind.BOOL, false));
            case INT -> ParsedDomain.leaf(parseLeafValues(cursor, LeafKind.INT, false));
            case FLOAT -> ParsedDomain.leaf(parseLeafValues(cursor, LeafKind.FLOAT, false));
            case STR -> ParsedDomain.leaf(parseLeafValues(cursor, LeafKind.LENGTH, true));
            case LIST, TUPLE, SET -> {
                List<? extends Number> size = parseLeafValues(cursor, LeafKind.LENGTH, true);
                cursor.expect('(');
                ParsedDomain child = parseDomainRec(spec.left, cursor);
                cursor.expect(')');
                yield ParsedDomain.unary(size, child);
            }
            case DICT -> {
                List<? extends Number> size = parseLeafValues(cursor, LeafKind.LENGTH, true);
                cursor.expect('(');
                ParsedDomain key = parseDomainRec(spec.left, cursor);
                cursor.expect(':');
                ParsedDomain val = parseDomainRec(spec.right, cursor);
                cursor.expect(')');
                yield ParsedDomain.binary(size, key, val);
            }
        };
    }

    @SuppressWarnings("unchecked")
    private static void assignDomain(APyNode<?> node, ParsedDomain parsed, boolean exhaustive) {
        if (exhaustive) {
            node.setExDomain(parsed.values);
        } else {
            node.setRanDomain(parsed.values);
        }

        if (parsed.left != null) {
            assignDomain(node.getLeftChild(), parsed.left, exhaustive);
        }
        if (parsed.right != null) {
            assignDomain(node.getRightChild(), parsed.right, exhaustive);
        }
    }

    private static List<? extends Number> parseLeafValues(DomainCursor cursor,
                                                           LeafKind leafKind,
                                                           boolean nonNegative)
            throws InvalidConfigException {
        if (cursor.consumeIf('[')) {
            List<String> tokens = new LinkedList<>();
            StringBuilder curr = new StringBuilder();
            while (!cursor.atEnd()) {
                char ch = cursor.peek();
                if (ch == ']') {
                    String tail = curr.toString().trim();
                    if (!tail.isEmpty()) {
                        tokens.add(tail);
                    }
                    cursor.advance();
                    return parseTokenList(tokens, leafKind, nonNegative);
                }
                if (ch == ',') {
                    tokens.add(curr.toString().trim());
                    curr.setLength(0);
                    cursor.advance();
                } else {
                    curr.append(ch);
                    cursor.advance();
                }
            }
            throw new InvalidConfigException("Unclosed array in domain");
        }

        String token = cursor.readUntilDelimiter();
        if (token.isEmpty() || token.contains(" ")) {
            throw new InvalidConfigException("Malformed domain token");
        }
        String[] parts = token.split("~", -1);
        if (parts.length != 2) {
            throw new InvalidConfigException("Range expected for domain token");
        }

        return parseRange(parts[0], parts[1], leafKind, nonNegative);
    }

    private static List<? extends Number> parseTokenList(List<String> tokens,
                                                          LeafKind leafKind,
                                                          boolean nonNegative)
            throws InvalidConfigException {
        if (tokens.isEmpty()) {
            return new ArrayList<>();
        }

        LinkedHashSet<Number> unique = new LinkedHashSet<>();
        for (String tok : tokens) {
            if (tok == null || tok.isEmpty()) {
                throw new InvalidConfigException("Malformed array domain");
            }
            Number val = parseSingleValue(tok, leafKind);
            validateLeafValue(val, leafKind, nonNegative);
            unique.add(val);
        }

        if (leafKind == LeafKind.FLOAT) {
            List<Double> out = new ArrayList<>();
            for (Number n : unique) {
                out.add(n.doubleValue());
            }
            return out;
        }

        List<Integer> out = new ArrayList<>();
        for (Number n : unique) {
            out.add(n.intValue());
        }
        return out;
    }

    private static List<? extends Number> parseRange(String left,
                                                     String right,
                                                     LeafKind leafKind,
                                                     boolean nonNegative)
            throws InvalidConfigException {
        if (left.isEmpty() || right.isEmpty()) {
            throw new InvalidConfigException("Malformed range");
        }

        Number lo = parseSingleValue(left, leafKind == LeafKind.FLOAT ? LeafKind.INT_OR_FLOAT
                : LeafKind.INT);
        Number hi = parseSingleValue(right, leafKind == LeafKind.FLOAT ? LeafKind.INT_OR_FLOAT
                : LeafKind.INT);

        if (leafKind != LeafKind.FLOAT
                && (isDecimalLiteral(left) || isDecimalLiteral(right))) {
            throw new InvalidConfigException("Non-integer range not allowed");
        }

        if (lo.doubleValue() > hi.doubleValue()) {
            throw new InvalidConfigException("Range lower bound exceeds upper bound");
        }

        if (leafKind == LeafKind.FLOAT && (isDecimalLiteral(left) || isDecimalLiteral(right))) {
            throw new InvalidConfigException("Float ranges must be integer endpoints");
        }

        int loInt = lo.intValue();
        int hiInt = hi.intValue();
        if (nonNegative && loInt < 0) {
            throw new InvalidConfigException("Negative values not allowed");
        }

        if (leafKind == LeafKind.FLOAT) {
            List<Double> out = new ArrayList<>();
            for (int x = loInt; x <= hiInt; x++) {
                out.add((double) x);
            }
            return out;
        }

        List<Integer> out = new ArrayList<>();
        for (int x = loInt; x <= hiInt; x++) {
            validateLeafValue(x, leafKind, nonNegative);
            out.add(x);
        }
        return out;
    }

    private static Number parseSingleValue(String token, LeafKind kind)
            throws InvalidConfigException {
        if (token.contains(" ")) {
            throw new InvalidConfigException("Whitespace not allowed");
        }

        try {
            return switch (kind) {
                case FLOAT, INT_OR_FLOAT -> {
                    if (token.contains(".")) {
                        yield Double.parseDouble(token);
                    }
                    yield Integer.parseInt(token);
                }
                case BOOL, INT, LENGTH -> {
                    if (token.contains(".")) {
                        throw new InvalidConfigException("Integer value expected");
                    }
                    yield Integer.parseInt(token);
                }
            };
        } catch (NumberFormatException ex) {
            throw new InvalidConfigException("Malformed numeric value");
        }
    }

    private static void validateLeafValue(Number value,
                                          LeafKind leafKind,
                                          boolean nonNegative)
            throws InvalidConfigException {
        if (nonNegative && value.intValue() < 0) {
            throw new InvalidConfigException("Negative values not allowed");
        }
        if (leafKind == LeafKind.BOOL) {
            int i = value.intValue();
            if (i != 0 && i != 1) {
                throw new InvalidConfigException("Boolean domain must use only 0 and 1");
            }
        }
    }

    private static Object parseJson(String text) throws InvalidConfigException {
        try {
            JsonCursor cursor = new JsonCursor(text);
            Object value = cursor.parseValue();
            cursor.skipWhitespace();
            if (!cursor.atEnd()) {
                throw new InvalidConfigException("Invalid JSON");
            }
            return value;
        } catch (InvalidConfigException ex) {
            throw ex;
        } catch (RuntimeException ex) {
            throw new InvalidConfigException("Invalid JSON");
        }
    }

    private static boolean containsWhitespace(String s) {
        for (int i = 0; i < s.length(); i++) {
            if (Character.isWhitespace(s.charAt(i))) {
                return true;
            }
        }
        return false;
    }

    private static boolean isDecimalLiteral(String token) {
        return token.contains(".");
    }

    private enum Kind {
        BOOL,
        INT,
        FLOAT,
        STR,
        LIST,
        TUPLE,
        SET,
        DICT
    }

    private enum LeafKind {
        BOOL,
        INT,
        FLOAT,
        LENGTH,
        INT_OR_FLOAT
    }

    private static class TypeSpec {
        private final Kind kind;
        private final String charDomain;
        private final TypeSpec left;
        private final TypeSpec right;

        private TypeSpec(Kind kind, String charDomain, TypeSpec left, TypeSpec right) {
            this.kind = kind;
            this.charDomain = charDomain;
            this.left = left;
            this.right = right;
        }

        private static TypeSpec prim(Kind kind) {
            return new TypeSpec(kind, null, null, null);
        }

        private static TypeSpec str(String chars) {
            return new TypeSpec(Kind.STR, chars, null, null);
        }

        private static TypeSpec unary(Kind kind, TypeSpec inner) {
            return new TypeSpec(kind, null, inner, null);
        }

        private static TypeSpec binary(Kind kind, TypeSpec left, TypeSpec right) {
            return new TypeSpec(kind, null, left, right);
        }
    }

    private static class ParsedDomain {
        private final List<? extends Number> values;
        private final ParsedDomain left;
        private final ParsedDomain right;

        private ParsedDomain(List<? extends Number> values, ParsedDomain left, ParsedDomain right) {
            this.values = values;
            this.left = left;
            this.right = right;
        }

        private static ParsedDomain leaf(List<? extends Number> values) {
            return new ParsedDomain(values, null, null);
        }

        private static ParsedDomain unary(List<? extends Number> values, ParsedDomain left) {
            return new ParsedDomain(values, left, null);
        }

        private static ParsedDomain binary(List<? extends Number> values,
                                           ParsedDomain left,
                                           ParsedDomain right) {
            return new ParsedDomain(values, left, right);
        }
    }

    private static class TypeCursor {
        private final String input;
        private int pos;

        private TypeCursor(String input) {
            this.input = input;
            this.pos = 0;
        }

        private int pos() {
            return this.pos;
        }

        private void setPos(int pos) {
            this.pos = pos;
        }

        private boolean atEnd() {
            return this.pos >= this.input.length();
        }

        private boolean startsWith(String token) {
            return this.input.startsWith(token, this.pos);
        }

        private void consume(String token) {
            this.pos += token.length();
        }

        private boolean consumeIf(char ch) {
            if (!atEnd() && this.input.charAt(this.pos) == ch) {
                this.pos++;
                return true;
            }
            return false;
        }

        private void expect(char ch) throws InvalidConfigException {
            if (atEnd() || this.input.charAt(this.pos) != ch) {
                throw new InvalidConfigException("Malformed type specification");
            }
            this.pos++;
        }

        private int indexOf(char ch) {
            return this.input.indexOf(ch, this.pos);
        }

        private String substring(int start, int end) {
            return this.input.substring(start, end);
        }
    }

    private static class DomainCursor {
        private final String input;
        private int pos;

        private DomainCursor(String input) {
            this.input = input;
            this.pos = 0;
        }

        private boolean atEnd() {
            return this.pos >= this.input.length();
        }

        private char peek() throws InvalidConfigException {
            if (atEnd()) {
                throw new InvalidConfigException("Unexpected end of domain");
            }
            return this.input.charAt(this.pos);
        }

        private void advance() {
            this.pos++;
        }

        private boolean consumeIf(char ch) {
            if (!atEnd() && this.input.charAt(this.pos) == ch) {
                this.pos++;
                return true;
            }
            return false;
        }

        private void expect(char ch) throws InvalidConfigException {
            if (!consumeIf(ch)) {
                throw new InvalidConfigException("Malformed domain specification");
            }
        }

        private String readUntilDelimiter() {
            int start = this.pos;
            while (!atEnd()) {
                char ch = this.input.charAt(this.pos);
                if (ch == '(' || ch == ')' || ch == ':') {
                    break;
                }
                this.pos++;
            }
            return this.input.substring(start, this.pos);
        }
    }

    private static class JsonCursor {
        private final String input;
        private int pos;

        private JsonCursor(String input) {
            this.input = input;
            this.pos = 0;
        }

        private boolean atEnd() {
            return this.pos >= this.input.length();
        }

        private void skipWhitespace() {
            while (!atEnd() && Character.isWhitespace(this.input.charAt(this.pos))) {
                this.pos++;
            }
        }

        private char peek() throws InvalidConfigException {
            if (atEnd()) {
                throw new InvalidConfigException("Unexpected end of JSON");
            }
            return this.input.charAt(this.pos);
        }

        private char next() throws InvalidConfigException {
            char ch = peek();
            this.pos++;
            return ch;
        }

        private boolean consumeIf(char ch) {
            if (!atEnd() && this.input.charAt(this.pos) == ch) {
                this.pos++;
                return true;
            }
            return false;
        }

        private void expect(char ch) throws InvalidConfigException {
            if (!consumeIf(ch)) {
                throw new InvalidConfigException("Invalid JSON");
            }
        }

        private void expectKeyword(String kw) throws InvalidConfigException {
            if (!this.input.startsWith(kw, this.pos)) {
                throw new InvalidConfigException("Invalid JSON");
            }
            this.pos += kw.length();
        }

        private Object parseValue() throws InvalidConfigException {
            skipWhitespace();
            char ch = peek();
            if (ch == '{') {
                return parseObject();
            }
            if (ch == '[') {
                return parseArray();
            }
            if (ch == '"') {
                return parseString();
            }
            if (ch == '-' || Character.isDigit(ch)) {
                return parseNumber();
            }
            if (this.input.startsWith("true", this.pos)) {
                expectKeyword("true");
                return Boolean.TRUE;
            }
            if (this.input.startsWith("false", this.pos)) {
                expectKeyword("false");
                return Boolean.FALSE;
            }
            if (this.input.startsWith("null", this.pos)) {
                expectKeyword("null");
                return null;
            }
            throw new InvalidConfigException("Invalid JSON");
        }

        private Map<String, Object> parseObject() throws InvalidConfigException {
            expect('{');
            skipWhitespace();

            java.util.LinkedHashMap<String, Object> out = new java.util.LinkedHashMap<>();
            if (consumeIf('}')) {
                return out;
            }

            while (true) {
                skipWhitespace();
                if (peek() != '"') {
                    throw new InvalidConfigException("Invalid JSON object key");
                }
                String key = parseString();
                skipWhitespace();
                expect(':');
                Object val = parseValue();
                out.put(key, val);
                skipWhitespace();
                if (consumeIf('}')) {
                    break;
                }
                expect(',');
            }
            return out;
        }

        private List<Object> parseArray() throws InvalidConfigException {
            expect('[');
            skipWhitespace();

            List<Object> out = new ArrayList<>();
            if (consumeIf(']')) {
                return out;
            }

            while (true) {
                Object val = parseValue();
                out.add(val);
                skipWhitespace();
                if (consumeIf(']')) {
                    break;
                }
                expect(',');
            }
            return out;
        }

        private String parseString() throws InvalidConfigException {
            expect('"');
            StringBuilder sb = new StringBuilder();
            while (true) {
                if (atEnd()) {
                    throw new InvalidConfigException("Unterminated string");
                }
                char ch = next();
                if (ch == '"') {
                    return sb.toString();
                }
                if (ch == '\\') {
                    if (atEnd()) {
                        throw new InvalidConfigException("Invalid escape sequence");
                    }
                    char esc = next();
                    switch (esc) {
                        case '"' -> sb.append('"');
                        case '\\' -> sb.append('\\');
                        case '/' -> sb.append('/');
                        case 'b' -> sb.append('\b');
                        case 'f' -> sb.append('\f');
                        case 'n' -> sb.append('\n');
                        case 'r' -> sb.append('\r');
                        case 't' -> sb.append('\t');
                        case 'u' -> {
                            if (this.pos + 4 > this.input.length()) {
                                throw new InvalidConfigException("Invalid unicode escape");
                            }
                            String hex = this.input.substring(this.pos, this.pos + 4);
                            try {
                                int code = Integer.parseInt(hex, 16);
                                sb.append((char) code);
                            } catch (NumberFormatException ex) {
                                throw new InvalidConfigException("Invalid unicode escape");
                            }
                            this.pos += 4;
                        }
                        default -> throw new InvalidConfigException("Invalid escape sequence");
                    }
                } else {
                    sb.append(ch);
                }
            }
        }

        private Number parseNumber() throws InvalidConfigException {
            int start = this.pos;
            if (consumeIf('-')) {
                // sign consumed
            }
            if (atEnd() || !Character.isDigit(this.input.charAt(this.pos))) {
                throw new InvalidConfigException("Invalid number");
            }
            while (!atEnd() && Character.isDigit(this.input.charAt(this.pos))) {
                this.pos++;
            }
            if (!atEnd() && this.input.charAt(this.pos) == '.') {
                this.pos++;
                if (atEnd() || !Character.isDigit(this.input.charAt(this.pos))) {
                    throw new InvalidConfigException("Invalid number");
                }
                while (!atEnd() && Character.isDigit(this.input.charAt(this.pos))) {
                    this.pos++;
                }
                String token = this.input.substring(start, this.pos);
                try {
                    return Double.parseDouble(token);
                } catch (NumberFormatException ex) {
                    throw new InvalidConfigException("Invalid number");
                }
            }

            String token = this.input.substring(start, this.pos);
            try {
                return Long.parseLong(token);
            } catch (NumberFormatException ex) {
                throw new InvalidConfigException("Invalid integer");
            }
        }
    }
}
